output.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?poet ?label ?birth ?death WHERE {
  ?poet wdt:P106 wd:Q36180 ; wdt:P21 wd:Q6581072 ; wdt:P19 ?birthplace .
  ?birthplace wdt:P131 + wd:Q5783 .
  OPTIONAL {
    ?poet rdfs:label ?label
    FILTER(lang(?label) = 'en')
  }
  OPTIONAL {
    ?poet wdt:P569 ?birth
  }
  OPTIONAL {
    ?poet wdt:P570 ?death
  }
}
